fn build_backend(name: &str, host: &str, port: u16, use_tls: bool) -> Result<Backend, Error> {
    let mut builder = BackendBuilder::new(name, host);

    builder.port(port);

    if use_tls {
        builder.enable_ssl();
        builder.sni_hostname(host);
        builder.check_certificate(true);
        builder.certificate_hostname(host);
        builder.min_tls_version("1.2");
        builder.max_tls_version("1.3");
    } else {
        builder.disable_ssl();
    }

    builder.connect_timeout(std::time::Duration::from_secs(2));
    builder.first_byte_timeout(std::time::Duration::from_secs(10));
    builder.between_bytes_timeout(std::time::Duration::from_secs(10));
    builder.tcp_keepalive_time(std::time::Duration::from_secs(60));

    builder.finish()
}

fn choose_backend(req: &Request<fastly::Body>) -> Result<Backend, Error> {
    let path = req.get_path();

    if path.starts_with("/api") {
        build_backend("api_backend", "api.example.com", 443, true)
    } else if path.starts_with("/static") {
        build_backend("static_backend", "static.example.com", 443, true)
    } else {
        build_backend("default_backend", "origin.example.com", 80, false)
    }
}

fn handle_backend_request(req: Request<fastly::Body>, backend: &Backend) -> Result<Response<fastly::Body>, Error> {
    let mut bereq = req;

    bereq.set_header("Host", backend.config().host().unwrap_or(""));

    bereq.send(backend)
}

